"use client";

import { useEffect, useRef } from "react";
import * as THREE from "three";
import { noise3D, lerp, lerpColor, SpringVector3 } from "@/lib/particleUtils";

interface ParticleFieldProps {
  scrollProgressRef: React.MutableRefObject<number>;
}

export default function ParticleField({ scrollProgressRef }: ParticleFieldProps) {
  const mountRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!mountRef.current) return;

    // Detect mobile touch devices (broad check)
    const isTouch = "ontouchstart" in window || navigator.maxTouchPoints > 0;
    const particleCount = typeof window !== "undefined" && window.innerWidth < 768 ? 40 : 120;

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
    camera.position.z = 15;

    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    mountRef.current.appendChild(renderer.domElement);

    // Geometry and Material
    const geometry = new THREE.BufferGeometry();
    const positions = new Float32Array(particleCount * 3);
    const colors = new Float32Array(particleCount * 3);
    const sizes = new Float32Array(particleCount);

    // Initial setups for base shapes
    const baseSpherePositions: THREE.Vector3[] = [];
    const baseExplodePositions: THREE.Vector3[] = [];
    const baseColumnPositions: THREE.Vector3[] = [];
    const springs: SpringVector3[] = [];
    const noiseOffsets: number[] = [];

    // Shader material for custom colors & fading via opacity
    const material = new THREE.ShaderMaterial({
      uniforms: {
        uTime: { value: 0 },
        uOpacity: { value: 1.0 },
      },
      transparent: true,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
      vertexShader: `
        attribute float size;
        varying vec3 vColor;
        void main() {
          vColor = color;
          vec4 mvPosition = modelViewMatrix * vec4(position, 1.0);
          gl_PointSize = size * (300.0 / -mvPosition.z);
          gl_Position = projectionMatrix * mvPosition;
        }
      `,
      fragmentShader: `
        uniform float uOpacity;
        varying vec3 vColor;
        void main() {
          // Soft circle
          float dist = length(gl_PointCoord - vec2(0.5));
          if (dist > 0.5) discard;
          float alpha = (0.5 - dist) * 2.0;
          gl_FragColor = vec4(vColor, alpha * uOpacity);
        }
      `
    });

    for (let i = 0; i < particleCount; i++) {
        // Base uniform sphere r=1.5
        const u = Math.random();
        const v = Math.random();
        const theta = 2 * Math.PI * u;
        const phi = Math.acos(2 * v - 1);
        const rTight = 1.5;
        const sx = rTight * Math.sin(phi) * Math.cos(theta);
        const sy = rTight * Math.sin(phi) * Math.sin(theta);
        const sz = rTight * Math.cos(phi);
        baseSpherePositions.push(new THREE.Vector3(sx, sy, sz));

        // Explode outward
        const mult = 4.0 + Math.random() * 4.0;
        baseExplodePositions.push(new THREE.Vector3(sx * mult, sy * mult, (sz * mult) - 2));

        // Flanking columns
        const colSide = i % 2 === 0 ? -1 : 1;
        const colX = colSide * (8 + Math.random() * 4);
        const colY = (Math.random() - 0.5) * 20;
        const colZ = (Math.random() - 0.5) * 5 - 2;
        baseColumnPositions.push(new THREE.Vector3(colX, colY, colZ));

        // Color mapped via HSL lerp
        const col = lerpColor(i / particleCount);
        colors[i * 3] = col.r;
        colors[i * 3 + 1] = col.g;
        colors[i * 3 + 2] = col.b;

        sizes[i] = Math.random() * 0.5 + 0.1;

        // Springs
        springs.push(new SpringVector3(new THREE.Vector3(sx, sy, sz), 0.02, 0.88));
        noiseOffsets.push(Math.random() * 100);
    }

    geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));
    geometry.setAttribute('size', new THREE.BufferAttribute(sizes, 1));

    const particleSystem = new THREE.Points(geometry, material);
    scene.add(particleSystem);

    // Mouse Tracking
    const mouse = new THREE.Vector2(-9999, -9999);

    const onMouseMove = (e: MouseEvent) => {
        if(isTouch) return;
        // Map to world space approx
        mouse.x = (e.clientX / window.innerWidth) * 2 - 1;
        mouse.y = -(e.clientY / window.innerHeight) * 2 + 1;
    };
    window.addEventListener('mousemove', onMouseMove);

    // Resize handler
    const onResize = () => {
        camera.aspect = window.innerWidth / window.innerHeight;
        camera.updateProjectionMatrix();
        renderer.setSize(window.innerWidth, window.innerHeight);
    };
    window.addEventListener('resize', onResize);

    // Frame Loop
    const clock = new THREE.Clock();
    let frameId: number;

    const tick = () => {
      const elapsed = clock.getElapsedTime();
      const progress = scrollProgressRef.current; // Directly read mapped progress

      material.uniforms.uTime.value = elapsed;

      // Calculate z receding parameter and opacity based on progress
      let zRecede = 0;
      let opacity = 1.0;
      if(progress > 0.8) {
          const tFade = (progress - 0.8) / 0.2; // 0 to 1
          opacity = lerp(1.0, 0.2, tFade);
          zRecede = lerp(0, -10, tFade);
      }
      material.uniforms.uOpacity.value = opacity;

      // Pre-compute mouse world pos bounds
      const vector = new THREE.Vector3(mouse.x, mouse.y, 0.5);
      vector.unproject(camera);
      const dir = vector.sub(camera.position).normalize();
      const distance = -camera.position.z / dir.z;
      const pos = camera.position.clone().add(dir.multiplyScalar(distance));

      const positionsAttr = geometry.attributes.position;

      for (let i = 0; i < particleCount; i++) {
          let baseTarget = new THREE.Vector3();

          // Scroll mapping targets
          if (progress < 0.2) {
              const t = progress / 0.2; // 0 to 1
              baseTarget.copy(baseSpherePositions[i]);
              // Idle noise drift in tight sphere
              baseTarget.x += noise3D(noiseOffsets[i] + elapsed * 0.2, 0, 0) * 0.2;
              baseTarget.y += noise3D(0, noiseOffsets[i] + elapsed * 0.2, 0) * 0.2;
          } else if (progress < 0.5) {
              const t = (progress - 0.2) / 0.3; // 0 to 1 explode
              baseTarget.lerpVectors(baseSpherePositions[i], baseExplodePositions[i], t);
              baseTarget.x += noise3D(noiseOffsets[i] + elapsed * 0.5, 0, 0) * 0.5;
              baseTarget.y += noise3D(0, noiseOffsets[i] + elapsed * 0.5, 0) * 0.5;
          } else {
              const t = Math.min(1.0, (progress - 0.5) / 0.3); // 0 to 1 columns
              baseTarget.lerpVectors(baseExplodePositions[i], baseColumnPositions[i], t);
              // Drift
              baseTarget.y += noise3D(0, noiseOffsets[i] + elapsed * 0.1, 0) * 1.5;
          }

          // Recede
          baseTarget.z += zRecede;

          // Mouse Attraction (effect radius: ~200px mapped to units)
          if (!isTouch) {
              const distToMouse = baseTarget.distanceTo(pos);
              if (distToMouse < 4.0) { // ~ world units rough equivalent
                // pull target toward mouse
                baseTarget.lerp(pos, 0.3 * (1 - distToMouse/4.0));
              }
          }

          springs[i].target.copy(baseTarget);
          springs[i].update();

          positionsAttr.setXYZ(i, springs[i].current.x, springs[i].current.y, springs[i].current.z);
      }

      positionsAttr.needsUpdate = true;
      renderer.render(scene, camera);
      frameId = requestAnimationFrame(tick);
    };

    tick();

    return () => {
        cancelAnimationFrame(frameId);
        window.removeEventListener('mousemove', onMouseMove);
        window.removeEventListener('resize', onResize);
        if (mountRef.current && renderer.domElement) {
            mountRef.current.removeChild(renderer.domElement);
        }
        renderer.dispose();
        geometry.dispose();
        material.dispose();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [scrollProgressRef]);

  // CSS structure keeps it fixed behind everything
  return (
    <div 
      ref={mountRef} 
      className="fixed top-0 left-0 w-full h-[40vh] md:h-screen z-[-1] pointer-events-auto mix-blend-screen"
    />
  );
}
